from pydantic import BaseModel

class RelevanceGrade(BaseModel):
    is_relevant: bool
    score: float  # 0.0 to 1.0

grader_llm = ChatOpenAI(model="gpt-4o-mini", temperature=0).with_structured_output(RelevanceGrade)

GRADE_PROMPT = """Does this document contain useful information to answer the question?
Score 0.0 (completely irrelevant) to 1.0 (directly answers the question).

Question: {question}
Document: {document}"""

def grade_documents(query: str, docs) -> list:
    """Return only documents that score >= 0.5 relevance."""
    relevant = []
    for doc in docs:
        grade = grader_llm.invoke(GRADE_PROMPT.format(question=query, document=doc.page_content[:500]))
        if grade.is_relevant and grade.score >= 0.5:
            relevant.append(doc)
    return relevant

def rewrite_query(query: str) -> str:
    prompt = (
        f"The following query returned irrelevant documents. Rewrite it to be more specific.\n"
        f"Return only the rewritten query.\n\nOriginal: {query}"
    )
    return llm.invoke(prompt).content.strip()

def self_rag(query: str, retriever, max_retries: int = 2) -> str:
    for attempt in range(max_retries + 1):
        docs = retriever.invoke(query)
        relevant_docs = grade_documents(query, docs)

        if relevant_docs:
            context = "\n\n".join(d.page_content for d in relevant_docs)
            return llm.invoke(f"Context:\n{context}\n\nQuestion: {query}").content

        if attempt < max_retries:
            query = rewrite_query(query)  # retry with rewritten query

    return llm.invoke(query).content  # fall back to no-retrieval

from langgraph.graph import StateGraph, END
from typing import TypedDict, Literal

class RAGState(TypedDict):
    query: str
    strategy: str
    documents: list
    rewrites: int
    answer: str

def classify_node(state: RAGState) -> RAGState:
    cls = classify_query(state["query"])
    return {**state, "strategy": cls.strategy}

def retrieve_node(state: RAGState) -> RAGState:
    docs = retriever.invoke(state["query"])
    return {**state, "documents": docs}

def grade_node(state: RAGState) -> RAGState:
    relevant = grade_documents(state["query"], state["documents"])
    return {**state, "documents": relevant}

def rewrite_node(state: RAGState) -> RAGState:
    new_q = rewrite_query(state["query"])
    return {**state, "query": new_q, "rewrites": state.get("rewrites", 0) + 1}

def generate_node(state: RAGState) -> RAGState:
    context = "\n\n".join(d.page_content for d in state["documents"])
    answer = llm.invoke(f"Context:\n{context}\n\nQ: {state['query']}").content
    return {**state, "answer": answer}

def route_strategy(state: RAGState) -> Literal["retrieve", "generate"]:
    return "generate" if state["strategy"] == "no_retrieval" else "retrieve"

def route_grade(state: RAGState) -> Literal["generate", "rewrite"]:
    if state["documents"]:
        return "generate"
    return "rewrite" if state.get("rewrites", 0) < 2 else "generate"

graph = StateGraph(RAGState)
graph.add_node("classify", classify_node)
graph.add_node("retrieve", retrieve_node)
graph.add_node("grade", grade_node)
graph.add_node("rewrite", rewrite_node)
graph.add_node("generate", generate_node)
graph.set_entry_point("classify")
graph.add_conditional_edges("classify", route_strategy)
graph.add_edge("retrieve", "grade")
graph.add_conditional_edges("grade", route_grade)
graph.add_edge("rewrite", "retrieve")
graph.add_edge("generate", END)
app = graph.compile()

result = app.invoke({"query": "What changed in the v2 API rate limits?", "rewrites": 0})
print(result["answer"])

from pydantic import BaseModel

class GroundingCheck(BaseModel):
    is_grounded: bool
    unsupported_claims: list[str]

grounding_llm = ChatOpenAI(model="gpt-4o", temperature=0).with_structured_output(GroundingCheck)

GROUNDING_PROMPT = """Check if every factual claim in the answer is directly supported by the context.

Context:
{context}

Answer:
{answer}

List any claims in the answer that are NOT found in the context."""

def check_grounding(answer: str, docs) -> GroundingCheck:
    context = "\n\n".join(d.page_content for d in docs)
    return grounding_llm.invoke(GROUNDING_PROMPT.format(context=context, answer=answer))

def adaptive_rag_with_grounding(query: str, retriever) -> dict:
    docs = retriever.invoke(query)
    relevant_docs = grade_documents(query, docs)

    if not relevant_docs:
        relevant_docs = docs  # fall back if grader too strict

    context = "\n\n".join(d.page_content for d in relevant_docs)
    answer = llm.invoke(f"Context:\n{context}\n\nQuestion: {query}").content

    grounding = check_grounding(answer, relevant_docs)
    return {
        "answer": answer,
        "is_grounded": grounding.is_grounded,
        "unsupported_claims": grounding.unsupported_claims,
        "confidence": "high" if grounding.is_grounded else "low"
    }
